// GENERATOR FUNCTIONS — Zero repetition guaranteed
// ═══════════════════════════════════════════════════════════════════════

export function getQuestionsBySubject(subject: string, count?: number): TestQuestion[] {
  const filtered = questionBank.filter(q => q.subject === subject);
  const shuffled = shuffleArray(filtered);
  return count ? shuffled.slice(0, count) : shuffled;
}

export function getQuestionsByChapter(chapter: string, count?: number): TestQuestion[] {
  const filtered = questionBank.filter(q => q.chapter === chapter);
  const shuffled = shuffleArray(filtered);
  return count ? shuffled.slice(0, count) : shuffled;
}

export function getChaptersWithQuestions(subject: string): { chapter: string; count: number }[] {
  const chapters: Record<string, number> = {};
  questionBank.filter(q => q.subject === subject).forEach(q => {
    chapters[q.chapter] = (chapters[q.chapter] || 0) + 1;
  });
  return Object.entries(chapters).map(([chapter, count]) => ({ chapter, count }));
}

// NO REPETITION: returns only unique questions, never duplicates
export function getMockTestQuestions(chapter: string, count: number = 50): TestQuestion[] {
  const available = questionBank.filter(q => q.pool === "mock" && q.chapter === chapter);
  if (available.length === 0) {
    const fallback = questionBank.filter(q => q.chapter === chapter);
    return shuffleArray(fallback).slice(0, Math.min(count, fallback.length));
  }
  return shuffleArray(available).slice(0, Math.min(count, available.length));
}

export function getWorksheetQuestions(chapter: string, count: number = 25): TestQuestion[] {
  const available = questionBank.filter(q => q.pool === "worksheet" && q.chapter === chapter);
  if (available.length === 0) {
    const fallback = questionBank.filter(q => q.chapter === chapter);
    return shuffleArray(fallback).slice(0, Math.min(count, fallback.length));
  }
  return shuffleArray(available).slice(0, Math.min(count, available.length));
}

export function getWeeklyTestQuestions(questionsPerSubject: number = 45): TestQuestion[] {
  const subjects = ["Botany", "Zoology", "Physics", "Chemistry"];
  const allQuestions: TestQuestion[] = [];
  subjects.forEach(subject => {
    const available = questionBank.filter(q => q.pool === "weekly" && q.subject === subject);
    if (available.length === 0) {
      const fallback = questionBank.filter(q => q.subject === subject);
      allQuestions.push(...shuffleArray(fallback).slice(0, Math.min(questionsPerSubject, fallback.length)));
    } else {
      allQuestions.push(...shuffleArray(available).slice(0, Math.min(questionsPerSubject, available.length)));
    }
  });
  return allQuestions;
}

export function getMonthlyTestQuestions(questionsPerSubject: number = 45): TestQuestion[] {
  const subjects = ["Botany", "Zoology", "Physics", "Chemistry"];
  const allQuestions: TestQuestion[] = [];
  subjects.forEach(subject => {
    const available = questionBank.filter(q => q.pool === "monthly" && q.subject === subject);
    if (available.length === 0) {
      const fallback = questionBank.filter(q => q.subject === subject);
      allQuestions.push(...shuffleArray(fallback).slice(0, Math.min(questionsPerSubject, fallback.length)));
    } else {
      allQuestions.push(...shuffleArray(available).slice(0, Math.min(questionsPerSubject, available.length)));
    }
  });
  return allQuestions;
}

export function getFullTestQuestions(questionsPerSubject: number = 45): TestQuestion[] {
  return getWeeklyTestQuestions(questionsPerSubject);
}

export { questionBank };
